(window.webpackJsonp=window.webpackJsonp||[]).push([[21],{338:function(t,n,e){"use strict";e.r(n);var r=e(17),s=Object(r.a)({},(function(){var t=this,n=t._self._c;return n("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[n("h1",{attrs:{id:"多进程一定比不上多线程么"}},[n("a",{staticClass:"header-anchor",attrs:{href:"#多进程一定比不上多线程么"}},[t._v("#")]),t._v(" 多进程一定比不上多线程么？")]),t._v(" "),n("p",[t._v("从Unix发展历史看，伴随着Unix的诞生多进程就出现了，而多线程很晚才被系统支持，例如Linux直到内核2.6，才支持符合Posix规范的NPTL线程库。进程和线程的特点，也就是各自的优缺点如下：")]),t._v(" "),n("p",[t._v("进程优点：编程、调试简单，可靠性较高。\n进程缺点：创建、销毁、切换速度慢，内存、资源占用大。\n线程优点：创建、销毁、切换速度快，内存、资源占用小。\n线程缺点：编程、调试复杂，可靠性较差。\n上面的对比可以归结为一句话：“线程快而进程可靠性高”。线程有个别名叫“轻量级进程”，在有的书籍资料上介绍线程可以十倍、百倍的效率快于进程； 而进程之间不共享数据，没有锁问题，结构简单，一个进程崩溃不像线程那样影响全局，因此比较可靠。我相信这个观点可以被大部分人所接受，因为和我们所接受的知识概念是相符的。")]),t._v(" "),n("p",[t._v("reference："),n("a",{attrs:{href:"https://link.zhihu.com/?target=https%3A//blog.csdn.net/kevin_lux/article/details/54967019",target:"_blank",rel:"noopener noreferrer"}},[t._v("https://blog.csdn.net/kevin_lux"),n("OutboundLink")],1)])])}),[],!1,null,null,null);n.default=s.exports}}]);